import (
	context "context"
	fern "github.com/server-sent-events/fern"
	fernclient "github.com/server-sent-events/fern/client"
)

client := fernclient.NewClient()
response, err := client.Completions.StreamWithoutTerminator(
	context.TODO(),
	&fern.StreamCompletionRequestWithoutTerminator{
		Query: "query",
	},
)

